import React, { useState, useEffect } from 'react';
import InputField from '../../../components/ui/InputField';
import SelectField from '../../../components/ui/SelectField';
import SaveButton from '../../../components/ui/SaveButton';

const COUNTRY_CITY_MAP = {
  "India": ["Mumbai", "Delhi", "Bangalore", "Hyderabad", "Chennai", "Kolkata", "Pune", "Ahmedabad", "Gurgaon", "Noida"],
  "United States": ["New York", "Los Angeles", "Chicago", "Houston", "Phoenix", "San Francisco", "Seattle", "Austin"],
  "United Kingdom": ["London", "Birmingham", "Manchester", "Glasgow", "Edinburgh", "Liverpool"],
  "Canada": ["Toronto", "Vancouver", "Montreal", "Calgary", "Ottawa"],
  "Australia": ["Sydney", "Melbourne", "Brisbane", "Perth", "Adelaide"],
  "United Arab Emirates": ["Dubai", "Abu Dhabi", "Sharjah"],
  "Singapore": ["Singapore"],
  "Germany": ["Berlin", "Munich", "Frankfurt", "Hamburg"],
  "France": ["Paris", "Marseille", "Lyon", "Toulouse"],
  "Japan": ["Tokyo", "Osaka", "Kyoto", "Yokohama"],
  "China": ["Beijing", "Shanghai", "Shenzhen", "Guangzhou"],
  "Brazil": ["Sao Paulo", "Rio de Janeiro", "Brasilia"],
  "South Africa": ["Johannesburg", "Cape Town", "Durban"],
  "Mexico": ["Mexico City", "Guadalajara", "Monterrey"],
  "Italy": ["Rome", "Milan", "Naples", "Turin"]
};

export default function BasicInfoTab({ profile, handleInputChange, handleSaveProfile, saving }) {
  const [manualCountry, setManualCountry] = useState(false);
  const [manualCity, setManualCity] = useState(false);

  useEffect(() => {
    if (profile.country && !Object.keys(COUNTRY_CITY_MAP).includes(profile.country)) {
      setManualCountry(true);
    }
    const currentCities = profile.country ? COUNTRY_CITY_MAP[profile.country] || [] : [];
    if (profile.city && profile.country && !currentCities.includes(profile.city)) {
      setManualCity(true);
    } else if (profile.city && !COUNTRY_CITY_MAP[profile.country]) {
      setManualCity(true);
    }
  }, [profile.country, profile.city]);

  const countryOptions = [...Object.keys(COUNTRY_CITY_MAP), 'Other'];
  const cityOptions = (profile.country && COUNTRY_CITY_MAP[profile.country] && !manualCountry)
    ? [...COUNTRY_CITY_MAP[profile.country], 'Other'] 
    : ['Other'];

  const handleCountrySelect = (e) => {
    const val = e.target.value;
    if (val === 'Other') {
      setManualCountry(true);
      handleInputChange({ target: { name: 'country', value: '', type: 'text' } });
      handleInputChange({ target: { name: 'city', value: '', type: 'text' } });
      setManualCity(true); // If country is manual, city must be manual
    } else {
      setManualCountry(false);
      handleInputChange({ target: { name: 'country', value: val, type: 'text' } });
      handleInputChange({ target: { name: 'city', value: '', type: 'text' } }); // reset city
      setManualCity(false);
    }
  };

  const handleCitySelect = (e) => {
    const val = e.target.value;
    if (val === 'Other') {
      setManualCity(true);
      handleInputChange({ target: { name: 'city', value: '', type: 'text' } });
    } else {
      setManualCity(false);
      handleInputChange({ target: { name: 'city', value: val, type: 'text' } });
    }
  };

  return (
    <div className="animate-in fade-in slide-in-from-right-4 duration-500">
      <h2 className="text-2xl font-black text-slate-900 mb-8">Basic Information</h2>
      
      <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6">
        <InputField label="Full Name" id="full_name" placeholder="e.g. John Doe" value={profile.full_name} onChange={handleInputChange}  />
        <InputField label="Email Address" id="email" type="email" placeholder="e.g. email@example.com" value={profile.email} onChange={handleInputChange} />
      </div>
      
      <InputField label="Current Job title" id="headline" placeholder="e.g. Senior Sales Executive | B2B SaaS | Revenue Driver" value={profile.headline} onChange={handleInputChange} />
      <InputField label="Current Industry" id="industry" placeholder="e.g. Software, Healthcare, Sales" value={profile.industry} onChange={handleInputChange} />
      
      <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6">
        <div>
          <SelectField 
            label="Country" id="country_select" value={manualCountry ? 'Other' : profile.country} onChange={handleCountrySelect} 
            options={countryOptions} 
          />
          {manualCountry && (
            <div className="mt-2 animate-in fade-in zoom-in duration-300">
              <InputField label="Enter Country" id="country" placeholder="e.g. Spain" value={profile.country} onChange={handleInputChange} />
            </div>
          )}
        </div>
        <div>
          <SelectField 
            label="City" id="city_select" value={manualCity ? 'Other' : profile.city} onChange={handleCitySelect} 
            options={cityOptions} 
          />
          {manualCity && (
            <div className="mt-2 animate-in fade-in zoom-in duration-300">
              <InputField label="Enter City" id="city" placeholder="e.g. Madrid" value={profile.city} onChange={handleInputChange} />
            </div>
          )}
        </div>
      </div>
      
      <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 mt-2">
        <InputField label="Phone Number" id="phone_number" placeholder="+91 9876543210" value={profile.phone_number} onChange={handleInputChange} />
        <InputField label="LinkedIn URL" id="linkedin_url" placeholder="e.g. linkedin.com/in/sales-pro" value={profile.linkedin_url} onChange={handleInputChange} />
      </div>

      <div className="mt-6">
        <SaveButton onSave={handleSaveProfile} saving={saving} />
      </div>
    </div>
  );
}